(function(){
'use strict';
if(window.CRMV94Official) return;
const D=document;
const $=(s,r=D)=>r.querySelector(s);
const $$=(s,r=D)=>Array.from(r.querySelectorAll(s));
const LEADS_KEY='outbounder_leads_v5';
const PB_KEY='crm_v93_playbooks';
const PIPE_KEY='crm_v94_pipeline_stages';
const FU_KEY='crm_v92_followup_stages';
const VERSION='V94';
const DEFAULT_PIPE=['Lead','Contato','Proposta','Fechado','Perdido'];
const DEFAULT_FU=['Primeiro contato','Segundo contato','Sem resposta','Retorno marcado','Aguardando resposta','Proposta enviada','Reativação'];
let currentView='inicio';
let pipelineTab='kanban';
let metricTab='geral';
let playbookTab='estrategia';
let selectedPB=null;
let leadFilter={q:'',pipeline:'',followup:'',origem:'',onlyToday:false};
function esc(v){return String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));}
function uid(p){return (p||'id')+'_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,8)}
function today(){return new Date().toISOString().slice(0,10)}
function tomorrow(){const d=new Date();d.setDate(d.getDate()+1);return d.toISOString().slice(0,10)}
function readJSON(k,f){try{const v=JSON.parse(localStorage.getItem(k)||'null');return v==null?f:v}catch(e){return f}}
function writeJSON(k,v){try{localStorage.setItem(k,JSON.stringify(v))}catch(e){console.warn('V94: falha ao salvar',k,e)}}
function asArr(v){return Array.isArray(v)?v:[]}
function getPipeStages(){const s=asArr(readJSON(PIPE_KEY,[])).filter(Boolean);return s.length?s:DEFAULT_PIPE.slice()}
function savePipeStages(st){writeJSON(PIPE_KEY,st.filter(Boolean))}
function getFuStages(){const raw=asArr(readJSON(FU_KEY,[]));const out=raw.map(x=>typeof x==='string'?x:(x&&x.nome)||'').filter(Boolean);return out.length?out:DEFAULT_FU.slice()}
function normLead(l){l=l||{};return Object.assign({id:l.id||l.leadId||uid('lead'),nome:l.nome||l.empresa||l.name||'Lead sem nome',empresa:l.empresa||l.nome||l.name||'Lead sem empresa',telefone:l.telefone||l.phone||'',cidade:l.cidade||l.city||'',segmento:l.segmento||l.segment||'Comercial',origem:l.origem||'CRM',campanha:l.campanha||'',responsavel:l.responsavel||'Você',prioridade:l.prioridade||'Média',valor:Number(l.valor||l.ticket||0),pipeline:l.pipeline||l.etapa||l.stage||getPipeStages()[0]||'Lead',followup:l.followup||l.followupStage||l.etapaFollowup||getFuStages()[0]||'Primeiro contato',proximaData:l.proximaData||l.nextDate||today(),proximaHora:l.proximaHora||l.nextTime||'10:00',contatos:Number(l.contatos||0),ligacoes:Number(l.ligacoes||0),whatsapps:Number(l.whatsapps||0),ultimoResultado:l.ultimoResultado||'',observacoes:l.observacoes||l.obs||'',historico:Array.isArray(l.historico)?l.historico:[]},l,{id:l.id||l.leadId||uid('lead')});}
function seedLeads(){return [
{id:'lead_demo_1',nome:'Barbearia Alfa',empresa:'Barbearia Alfa',segmento:'Barbearia',telefone:'51999990001',cidade:'Porto Alegre',origem:'Garimpo',campanha:'Barbearias POA',prioridade:'Alta',valor:3200,pipeline:'Lead',followup:'Primeiro contato',proximaData:today(),proximaHora:'10:00',contatos:0,ligacoes:0,whatsapps:0,ultimoResultado:'',historico:[]},
{id:'lead_demo_2',nome:'Clínica Bella',empresa:'Clínica Bella',segmento:'Estética',telefone:'53999990002',cidade:'Pelotas',origem:'Garimpo',campanha:'Estética Sul',prioridade:'Alta',valor:4800,pipeline:'Contato',followup:'Retorno marcado',proximaData:today(),proximaHora:'15:30',contatos:2,ligacoes:1,whatsapps:1,ultimoResultado:'Pediu retorno',historico:[{tipo:'Ligação',resultado:'Pediu retorno',data:today(),hora:'09:20',obs:'Pediu para chamar à tarde.'}]},
{id:'lead_demo_3',nome:'Studio Prime',empresa:'Studio Prime',segmento:'Salão',telefone:'51988880003',cidade:'Canoas',origem:'Indicação',campanha:'Indicação',prioridade:'Média',valor:2500,pipeline:'Proposta',followup:'Aguardando resposta',proximaData:tomorrow(),proximaHora:'11:00',contatos:4,ligacoes:2,whatsapps:2,ultimoResultado:'Proposta enviada',historico:[{tipo:'WhatsApp',resultado:'Proposta enviada',data:today(),hora:'11:10',obs:'Aguardando resposta.'}]}];}
function getLeads(){let arr=asArr(readJSON(LEADS_KEY,[])).map(normLead);if(!arr.length){arr=seedLeads();writeJSON(LEADS_KEY,arr)}return arr}
function saveLeads(arr){writeJSON(LEADS_KEY,arr.map(normLead));try{D.dispatchEvent(new CustomEvent('crm:leads-updated',{detail:{source:'v94'}}))}catch(e){}}
function defaultPlaybooks(){return [{id:'pb_garimpo',nome:'Primeiro contato — Garimpo',segmento:'Geral',etapa:'Primeiro contato',canal:'Ligação',script:{abertura:'Oi, {nome_lead}, tudo bem? Aqui é o {responsavel}. Vi que a {empresa} trabalha com {segmento} em {cidade}.',contexto:'Estou te chamando porque muitos negócios perdem agendamentos quando o cliente chama no WhatsApp e não recebe retorno no tempo certo.',diagnostico:'Hoje vocês conseguem acompanhar todos os contatos, retornos e clientes que somem antes de marcar horário?',valor:'A ideia é organizar contatos, retornos e follow-ups para aumentar agendamentos sem precisar depender só de anúncio.',fechamento:'Faz sentido eu te mostrar isso em uma reunião rápida de 10 minutos?',whatsapp:'Oi, {nome_lead}. Tentei falar contigo sobre uma forma de organizar melhor os contatos e retornos da {empresa}. Posso te mandar por aqui?'},objecoes:[{nome:'Sem tempo',resposta:'Claro. Melhor eu te chamar no fim da tarde ou amanhã de manhã?'},{nome:'Manda no WhatsApp',resposta:'Te mando sim. Para eu não mandar algo genérico, hoje vocês querem melhorar mais atendimento, agendamento ou retorno?'}],cadencia:['Dia 0 — Ligação','Dia 0 — WhatsApp pós-ligação','Dia 2 — Follow-up','Dia 4 — Segunda tentativa']}];}
function normPB(p){p=p||{};const script=Object.assign({abertura:'',contexto:'',diagnostico:'',valor:'',fechamento:'',whatsapp:''},p.script||{});return {id:p.id||uid('pb'),nome:p.nome||p.name||'Playbook sem nome',segmento:p.segmento||'Geral',etapa:p.etapa||'Primeiro contato',canal:p.canal||'Ligação',script, objecoes:Array.isArray(p.objecoes)?p.objecoes:[], cadencia:Array.isArray(p.cadencia)?p.cadencia:[]};}
function getPlaybooks(){let p=asArr(readJSON(PB_KEY,[])).map(normPB);if(!p.length){p=defaultPlaybooks();writeJSON(PB_KEY,p)}return p}
function savePlaybooks(p){writeJSON(PB_KEY,p.map(normPB))}
function fill(text,lead){const map={nome_lead:lead.nome||lead.empresa,empresa:lead.empresa||lead.nome,cidade:lead.cidade,segmento:lead.segmento,campanha:lead.campanha,origem:lead.origem,etapa_pipeline:lead.pipeline,followup:lead.followup,responsavel:lead.responsavel,telefone:lead.telefone};return String(text||'').replace(/\{([^}]+)\}/g,(m,k)=>esc(map[k]||''));}
function choosePB(lead){const ps=getPlaybooks();return ps.find(p=>p.etapa===lead.followup)||ps.find(p=>p.segmento===lead.segmento)||ps[0]||defaultPlaybooks()[0]}
function kpis(leads){leads=leads||getLeads();return {total:leads.length,valor:leads.reduce((s,l)=>s+Number(l.valor||0),0),hoje:leads.filter(l=>l.proximaData===today()).length,vencidos:leads.filter(l=>l.proximaData&&l.proximaData<today()).length,propostas:leads.filter(l=>/proposta/i.test(l.pipeline)).length,fechados:leads.filter(l=>/fechado/i.test(l.pipeline)).length,perdidos:leads.filter(l=>/perdido/i.test(l.pipeline)).length,contatos:leads.reduce((s,l)=>s+Number(l.contatos||0),0)};}
function setOnlyView(view){currentView=view;if(view==='dashboard'||view==='perdas')view='metricas';$$('.view').forEach(v=>v.classList.toggle('active',v.id===view));$$('[data-view],[data-go-view]').forEach(n=>{const val=n.getAttribute('data-view')||n.getAttribute('data-go-view');n.classList.toggle('active',val===view)});try{localStorage.setItem('crm_current_view',view);history.replaceState(null,'','#'+view)}catch(e){}}
function hero(title,desc,actions){return '<div class="v94-hero"><div class="v94-hero-row"><div><div class="v94-eyebrow">CRM oficial '+VERSION+'</div><h1>'+esc(title)+'</h1><p>'+esc(desc)+'</p></div><div class="v94-actions">'+(actions||'')+'</div></div></div>'}
function kpiGrid(items){return '<div class="v94-kpis">'+items.map(i=>'<div class="v94-kpi"><span>'+esc(i.label)+'</span><strong>'+esc(i.value)+'</strong></div>').join('')+'</div>'}
function badge(t,cls){return '<span class="v94-badge '+(cls||'')+'">'+esc(t)+'</span>'}
function leadCard(l){return '<div class="v94-card" data-v94-card-lead="'+esc(l.id)+'"><div><div class="v94-card-title">'+esc(l.empresa||l.nome)+'</div><div class="v94-muted">'+esc(l.segmento)+' · '+esc(l.cidade||'sem cidade')+' · '+esc(l.telefone||'sem telefone')+'</div><div class="v94-badges">'+badge(l.prioridade,l.prioridade==='Alta'?'hot':'')+badge('Pipeline: '+l.pipeline)+badge('Follow-up: '+l.followup)+badge((l.contatos||0)+' contatos','green')+'</div></div><div class="v94-actions"><button class="v94-btn soft" data-v95-open-lead="'+esc(l.id)+'">Abrir ficha</button></div></div>'}
function route(view){if(!view)return;if(view==='dashboard'||view==='perdas')view='metricas';setOnlyView(view);if(view==='leads'||view==='novo-lead')renderLeads(view==='novo-lead');else if(view==='playbooks')renderPlaybooks();else if(view==='pipeline')renderPipeline();else if(view==='metricas')renderMetricas();else if(view==='garimpo'&&window.CRMV93Official)window.CRMV93Official.renderGarimpo();else if(view==='ligacoes'&&window.CRMV93Official)window.CRMV93Official.renderLigacoes();else if(view==='cadencias'&&window.CRMV93Official)window.CRMV93Official.renderFollowup();else if(view==='inicio')renderHomeEnhancement();}
function filteredLeads(){const q=(leadFilter.q||'').toLowerCase();return getLeads().filter(l=>(!q||[l.nome,l.empresa,l.telefone,l.cidade,l.segmento,l.origem,l.campanha].join(' ').toLowerCase().includes(q))&&(!leadFilter.pipeline||l.pipeline===leadFilter.pipeline)&&(!leadFilter.followup||l.followup===leadFilter.followup)&&(!leadFilter.origem||l.origem===leadFilter.origem)&&(!leadFilter.onlyToday||l.proximaData<=today()));}
function renderLeads(openNew){const el=$('#leads');if(!el)return;const leads=filteredLeads();const all=getLeads();const s=kpis(all);const pipes=getPipeStages(), fus=getFuStages();const origens=[...new Set(all.map(l=>l.origem||'CRM'))];el.innerHTML='<div class="v94-shell">'+hero('Central de Leads Profissional','Todos os leads ficam em uma ficha única. A mesma informação alimenta Ligações, Follow-up, Pipeline, Playbooks e Métricas.','<button class="v94-btn primary" data-v94-action="new-lead">Novo lead</button><button class="v94-btn soft" data-v94-action="export-leads">Exportar</button>')+kpiGrid([{label:'Leads',value:s.total},{label:'Valor em pipeline',value:'R$ '+s.valor.toLocaleString('pt-BR')},{label:'Ações hoje',value:s.hoje},{label:'Vencidos',value:s.vencidos}])+'<div class="v94-panel"><div class="v94-toolbar"><input class="v94-input" style="max-width:320px" data-v94-filter="q" placeholder="Buscar por nome, cidade, telefone, campanha..." value="'+esc(leadFilter.q)+'"><select class="v94-input" style="max-width:190px" data-v94-filter="pipeline"><option value="">Pipeline</option>'+pipes.map(p=>'<option '+(leadFilter.pipeline===p?'selected':'')+'>'+esc(p)+'</option>').join('')+'</select><select class="v94-input" style="max-width:210px" data-v94-filter="followup"><option value="">Follow-up</option>'+fus.map(f=>'<option '+(leadFilter.followup===f?'selected':'')+'>'+esc(f)+'</option>').join('')+'</select><select class="v94-input" style="max-width:190px" data-v94-filter="origem"><option value="">Origem</option>'+origens.map(o=>'<option '+(leadFilter.origem===o?'selected':'')+'>'+esc(o)+'</option>').join('')+'</select><button class="v94-btn '+(leadFilter.onlyToday?'primary':'soft')+'" data-v94-action="toggle-today">Hoje/vencidos</button><button class="v94-btn" data-v94-action="clear-filters">Limpar</button></div><div class="v94-table-wrap"><table class="v94-table"><thead><tr><th>Lead</th><th>Telefone</th><th>Cidade</th><th>Origem</th><th>Pipeline</th><th>Follow-up</th><th>Próxima ação</th><th></th></tr></thead><tbody>'+leads.map(l=>'<tr><td><b>'+esc(l.empresa||l.nome)+'</b><div class="v94-muted">'+esc(l.segmento)+' · '+esc(l.campanha||'sem campanha')+'</div></td><td>'+esc(l.telefone||'-')+'</td><td>'+esc(l.cidade||'-')+'</td><td>'+esc(l.origem||'-')+'</td><td>'+badge(l.pipeline)+'</td><td>'+badge(l.followup,'green')+'</td><td>'+esc(l.proximaData||'-')+' '+esc(l.proximaHora||'')+'</td><td><button class="v94-btn soft" data-v95-open-lead="'+esc(l.id)+'">Abrir</button></td></tr>').join('')+'</tbody></table></div></div></div>';bindLeads();if(openNew)setTimeout(()=>openLeadDrawer('new'),50);}
function bindLeads(){const el=$('#leads');if(!el||el._v94Bound){return}el._v94Bound=true;el.addEventListener('input',e=>{const f=e.target.closest('[data-v94-filter]');if(!f)return;leadFilter[f.dataset.v94Filter]=f.value;renderLeads();});el.addEventListener('change',e=>{const f=e.target.closest('[data-v94-filter]');if(!f)return;leadFilter[f.dataset.v94Filter]=f.value;renderLeads();});el.addEventListener('click',e=>{const a=e.target.closest('[data-v94-action]');if(!a)return;const act=a.dataset.v94Action;if(act==='new-lead')openLeadDrawer('new');if(act==='toggle-today'){leadFilter.onlyToday=!leadFilter.onlyToday;renderLeads()}if(act==='clear-filters'){leadFilter={q:'',pipeline:'',followup:'',origem:'',onlyToday:false};renderLeads()}if(act==='export-leads'){downloadJSON(getLeads(),'leads-crm-v94.json')}})}
function renderPipeline(mode){try{if(mode){const map={kanban:'kanban',tabela:'table',table:'table',funil:'funnel',funnel:'funnel'};localStorage.setItem('crm_v65_pipeline_view',map[mode]||mode)}const el=$('#pipeline');if(el){el.classList.remove('v94-pipeline-view','v881-pipeline-v79-imagem');el.classList.add('pipeline-v65');el.removeAttribute('data-v94-ready')}if(window.CRMV65Pipeline&&typeof window.CRMV65Pipeline.render==='function')return window.CRMV65Pipeline.render()}catch(e){console.warn('[V98] Pipeline V65 não renderizou',e)}}
function renderPipelineTab(tab){return renderPipeline(tab)}
function bindPipeline(){}
function renderMetricas(){const el=$('#metricas');if(!el)return;const leads=getLeads(), s=kpis(leads);el.innerHTML='<div class="v94-shell">'+hero('Métricas Executivas','Dashboard, perdas, campanhas e atividades em uma aba única, sem voltar para páginas antigas separadas.','<button class="v94-btn primary" data-v94-met-tab="geral">Atualizar</button><button class="v94-btn soft" data-v94-met-tab="perdas">Ver perdas</button>')+kpiGrid([{label:'Leads',value:s.total},{label:'Valor total',value:'R$ '+s.valor.toLocaleString('pt-BR')},{label:'Contatos feitos',value:s.contatos},{label:'Taxa proposta',value:(s.total?Math.round((s.propostas/s.total)*100):0)+'%'}])+'<div class="v94-tabs"><button class="v94-tab '+(metricTab==='geral'?'active':'')+'" data-v94-met-tab="geral">Visão geral</button><button class="v94-tab '+(metricTab==='perdas'?'active':'')+'" data-v94-met-tab="perdas">Perdas</button><button class="v94-tab '+(metricTab==='campanhas'?'active':'')+'" data-v94-met-tab="campanhas">Campanhas</button><button class="v94-tab '+(metricTab==='atividades'?'active':'')+'" data-v94-met-tab="atividades">Atividades</button></div><div id="v94MetBody"></div></div>';bindMetricas();renderMetricasTab(metricTab);}
function renderMetricasTab(tab){metricTab=tab;const b=$('#v94MetBody');if(!b)return;$$('[data-v94-met-tab]').forEach(x=>x.classList.toggle('active',x.dataset.v94MetTab===tab));const leads=getLeads(), stages=getPipeStages();if(tab==='geral'){b.innerHTML='<div class="v94-grid"><div class="v94-panel"><h2>Pipeline por etapa</h2>'+stages.map(st=>{const arr=leads.filter(l=>l.pipeline===st);return '<div class="v94-card"><div><b>'+esc(st)+'</b><div class="v94-muted">'+arr.length+' leads · R$ '+arr.reduce((s,l)=>s+Number(l.valor||0),0).toLocaleString('pt-BR')+'</div></div><button class="v94-btn soft" data-v94-go-pipeline="'+esc(st)+'">Abrir pipeline</button></div>'}).join('')+'</div><div class="v94-panel"><h2>Riscos e próximas ações</h2>'+leads.filter(l=>(l.proximaData&&l.proximaData<=today())||l.followup==='Sem resposta').slice(0,8).map(leadCard).join('')+'</div></div>'}if(tab==='perdas'){const lost=leads.filter(l=>/perdido/i.test(l.pipeline));b.innerHTML='<div class="v94-panel"><h2>Leads perdidos</h2>'+(lost.length?lost.map(leadCard).join(''):'<div class="v94-empty">Nenhuma perda registrada.</div>')+'</div>'}if(tab==='campanhas'){const groups=leads.reduce((g,l)=>{const k=l.campanha||l.origem||'Sem origem';g[k]=g[k]||[];g[k].push(l);return g},{});b.innerHTML='<div class="v94-panel"><h2>Origem e campanhas</h2>'+Object.keys(groups).map(k=>'<div class="v94-card"><div><b>'+esc(k)+'</b><div class="v94-muted">'+groups[k].length+' leads · R$ '+groups[k].reduce((s,l)=>s+Number(l.valor||0),0).toLocaleString('pt-BR')+'</div></div>'+badge(groups[k].filter(l=>/proposta|fechado/i.test(l.pipeline)).length+' avançados','green')+'</div>').join('')+'</div>'}if(tab==='atividades'){const acts=leads.flatMap(l=>(l.historico||[]).map(h=>({l,h}))).slice(-40).reverse();b.innerHTML='<div class="v94-panel"><h2>Atividades recentes</h2>'+(acts.map(x=>'<div class="v94-event"><b>'+esc(x.l.empresa)+' — '+esc(x.h.tipo||'Evento')+'</b><div>'+esc(x.h.resultado||'')+' · '+esc(x.h.data||'')+' '+esc(x.h.hora||'')+'</div></div>').join('')||'<div class="v94-empty">Sem atividades registradas ainda.</div>')+'</div>'}}
function bindMetricas(){const el=$('#metricas');if(!el||el._v94Bound)return;el._v94Bound=true;el.addEventListener('click',e=>{const t=e.target.closest('[data-v94-met-tab]');if(t)renderMetricasTab(t.dataset.v94MetTab);const p=e.target.closest('[data-v94-go-pipeline]');if(p)route('pipeline')})}
function renderPlaybooks(){const el=$('#playbooks');if(!el)return;const ps=getPlaybooks();if(!selectedPB||!ps.find(p=>p.id===selectedPB))selectedPB=ps[0]?.id||null;el.className='view grid-view v94-official-view v94-playbooks-view'+(el.classList.contains('active')?' active':'');el.innerHTML='<div class="v94-shell">'+hero('Playbooks comerciais','Agora a aba começa direto na versão correta: estratégia, scripts personalizáveis, cadências e prévia com dados reais do lead. Sem bloco antigo no topo.','<button class="v94-btn primary" data-v94-pb-action="new">Criar playbook</button><button class="v94-btn soft" data-v94-pb-action="export">Exportar</button>')+kpiGrid([{label:'Playbooks',value:ps.length},{label:'Scripts',value:ps.reduce((s,p)=>s+Object.keys(p.script||{}).length,0)},{label:'Cadências',value:ps.reduce((s,p)=>s+(p.cadencia||[]).length,0)},{label:'Objeções',value:ps.reduce((s,p)=>s+(p.objecoes||[]).length,0)}])+'<div class="v94-tabs"><button class="v94-tab '+(playbookTab==='estrategia'?'active':'')+'" data-v94-pb-tab="estrategia">Estratégia</button><button class="v94-tab '+(playbookTab==='scripts'?'active':'')+'" data-v94-pb-tab="scripts">Script Builder</button><button class="v94-tab '+(playbookTab==='personalizacao'?'active':'')+'" data-v94-pb-tab="personalizacao">Personalização</button><button class="v94-tab '+(playbookTab==='cadencias'?'active':'')+'" data-v94-pb-tab="cadencias">Cadências</button><button class="v94-tab '+(playbookTab==='previa'?'active':'')+'" data-v94-pb-tab="previa">Prévia com lead</button></div><div id="v94PbBody"></div></div>';bindPlaybooks();renderPbTab(playbookTab);}
function currentPB(){return getPlaybooks().find(p=>p.id===selectedPB)||getPlaybooks()[0]||normPB({})}
function pbList(){const ps=getPlaybooks();return '<div class="v94-card-list">'+ps.map(p=>'<div class="v94-card"><div><b>'+esc(p.nome)+'</b><div class="v94-muted">'+esc(p.canal)+' · '+esc(p.segmento)+' · '+esc(p.etapa)+'</div></div><button class="v94-btn '+(p.id===selectedPB?'primary':'soft')+'" data-v94-pb-select="'+esc(p.id)+'">Selecionar</button></div>').join('')+'</div>'}
function renderPbTab(tab){playbookTab=tab;const b=$('#v94PbBody');if(!b)return;$$('[data-v94-pb-tab]').forEach(x=>x.classList.toggle('active',x.dataset.v94PbTab===tab));const p=currentPB();if(tab==='estrategia'){b.innerHTML='<div class="v94-grid"><div class="v94-panel"><h2>Biblioteca limpa</h2>'+pbList()+'</div><div class="v94-panel"><h2>Como o Playbook é escolhido</h2><p class="v94-muted">O CRM cruza segmento, etapa de Follow-up e situação do lead. Quando a ligação começa, o script aparece sozinho e os placeholders são substituídos pelos dados reais.</p><div class="v94-card-list"><div class="v94-card"><b>1. Lead entra pelo Garimpo/Leads</b>'+badge('ID único','green')+'</div><div class="v94-card"><b>2. Follow-up define o momento da conversa</b>'+badge('Primeiro contato, retorno, proposta')+'</div><div class="v94-card"><b>3. Playbook entrega o roteiro certo</b>'+badge('Sem procurar aba')+'</div></div></div></div>'}if(tab==='scripts'){const s=p.script||{};b.innerHTML='<div class="v94-grid"><div class="v94-panel"><h2>Script Builder</h2><div class="v94-fieldgrid"><div class="v94-field"><label>Nome</label><input data-v94-pb-field="nome" value="'+esc(p.nome)+'"></div><div class="v94-field"><label>Segmento</label><input data-v94-pb-field="segmento" value="'+esc(p.segmento)+'"></div><div class="v94-field"><label>Etapa</label><select data-v94-pb-field="etapa">'+getFuStages().map(f=>'<option '+(p.etapa===f?'selected':'')+'>'+esc(f)+'</option>').join('')+'</select></div></div>'+['abertura','contexto','diagnostico','valor','fechamento','whatsapp'].map(k=>'<div class="v94-field" style="margin-top:12px"><label>'+esc(k)+'</label><textarea data-v94-pb-script="'+k+'">'+esc(s[k]||'')+'</textarea></div>').join('')+'<div class="v94-toolbar" style="margin-top:12px"><button class="v94-btn primary" data-v94-pb-action="save">Salvar script</button><button class="v94-btn soft" data-v94-pb-action="copy-placeholders">Copiar placeholders</button></div></div><div class="v94-panel"><h2>Placeholders disponíveis</h2><div class="v94-badges">'+['{nome_lead}','{empresa}','{cidade}','{segmento}','{campanha}','{origem}','{etapa_pipeline}','{followup}','{responsavel}','{telefone}'].map(x=>badge(x,'green')).join('')+'</div><p class="v94-muted" style="margin-top:12px">Esses campos entram automaticamente quando a ligação começa ou quando você gera a prévia do script.</p></div></div>'}if(tab==='personalizacao'){b.innerHTML='<div class="v94-grid"><div class="v94-panel"><h2>Objeções</h2><p class="v94-muted">Uma objeção por linha no formato: Objeção | Resposta</p><textarea class="v94-input" style="min-height:230px" data-v94-pb-objections>'+esc((p.objecoes||[]).map(o=>(o.nome||'')+' | '+(o.resposta||'')).join('\n'))+'</textarea><button class="v94-btn primary" style="margin-top:12px" data-v94-pb-action="save">Salvar objeções</button></div><div class="v94-panel"><h2>Uso durante a ligação</h2><p class="v94-muted">As objeções ficam escondidas no Modo Ligação e aparecem só quando precisar. Isso evita textão e deixa o roteiro como guia, não como fala robótica.</p></div></div>'}if(tab==='cadencias'){b.innerHTML='<div class="v94-grid"><div class="v94-panel"><h2>Cadência</h2><p class="v94-muted">Uma ação por linha.</p><textarea class="v94-input" style="min-height:230px" data-v94-pb-cadence>'+esc((p.cadencia||[]).join('\n'))+'</textarea><button class="v94-btn primary" style="margin-top:12px" data-v94-pb-action="save">Salvar cadência</button></div><div class="v94-panel"><h2>Exemplo</h2><div class="v94-card-list">'+(p.cadencia||[]).map(c=>'<div class="v94-card"><b>'+esc(c)+'</b></div>').join('')+'</div></div></div>'}if(tab==='previa'){const leads=getLeads();const l=leads[0]||{};b.innerHTML='<div class="v94-grid"><div class="v94-panel"><h2>Prévia personalizada</h2><div class="v94-field"><label>Lead</label><select data-v94-pb-preview-lead>'+leads.map(x=>'<option value="'+esc(x.id)+'">'+esc(x.empresa||x.nome)+'</option>').join('')+'</select></div><div id="v94PbPreview" style="margin-top:14px">'+renderPBPreview(p,l)+'</div></div><div class="v94-panel"><h2>Biblioteca</h2>'+pbList()+'</div></div>'}}
function renderPBPreview(p,l){return '<div class="v94-card-list">'+['abertura','contexto','diagnostico','valor','fechamento','whatsapp'].map(k=>'<div class="v94-card"><div><b>'+esc(k)+'</b><div class="v94-muted">'+fill((p.script||{})[k]||'',l||{})+'</div></div><button class="v94-btn soft" data-v94-copy-text="'+esc(fill((p.script||{})[k]||'',l||{}))+'">Copiar</button></div>').join('')+'</div>'}
function saveCurrentPBFromDOM(){const ps=getPlaybooks();let p=ps.find(x=>x.id===selectedPB);if(!p)return;$$('[data-v94-pb-field]').forEach(i=>{p[i.dataset.v94PbField]=i.value});$$('[data-v94-pb-script]').forEach(i=>{p.script=p.script||{};p.script[i.dataset.v94PbScript]=i.value});const obj=$('[data-v94-pb-objections]');if(obj){p.objecoes=obj.value.split('\n').map(line=>line.trim()).filter(Boolean).map(line=>{const parts=line.split('|');return {nome:(parts[0]||'').trim(),resposta:(parts.slice(1).join('|')||'').trim()}})}const cad=$('[data-v94-pb-cadence]');if(cad){p.cadencia=cad.value.split('\n').map(x=>x.trim()).filter(Boolean)}savePlaybooks(ps);renderPlaybooks()}
function bindPlaybooks(){const el=$('#playbooks');if(!el||el._v94Bound)return;el._v94Bound=true;el.addEventListener('click',e=>{const tab=e.target.closest('[data-v94-pb-tab]');if(tab){renderPbTab(tab.dataset.v94PbTab);return}const sel=e.target.closest('[data-v94-pb-select]');if(sel){selectedPB=sel.dataset.v94PbSelect;renderPbTab(playbookTab);return}const copy=e.target.closest('[data-v94-copy-text]');if(copy){copyText(copy.dataset.v94CopyText);return}const act=e.target.closest('[data-v94-pb-action]');if(!act)return;const a=act.dataset.v94PbAction;if(a==='new'){const ps=getPlaybooks();const p=normPB({nome:'Novo playbook',script:{abertura:'Oi, {nome_lead}. Posso te explicar rapidamente o motivo do contato?',contexto:'Estou entrando em contato por causa da {empresa}.',diagnostico:'Como vocês acompanham os retornos hoje?',valor:'A ideia é organizar melhor o processo comercial.',fechamento:'Faz sentido uma conversa rápida?',whatsapp:'Oi, {nome_lead}. Tentei falar contigo sobre a {empresa}.'},cadencia:['Dia 0 — Ligação']});ps.push(p);savePlaybooks(ps);selectedPB=p.id;playbookTab='scripts';renderPlaybooks()}if(a==='save')saveCurrentPBFromDOM();if(a==='export')downloadJSON(getPlaybooks(),'playbooks-crm-v94.json');if(a==='copy-placeholders')copyText('{nome_lead} {empresa} {cidade} {segmento} {campanha} {origem} {etapa_pipeline} {followup} {responsavel} {telefone}')});el.addEventListener('change',e=>{const pLead=e.target.closest('[data-v94-pb-preview-lead]');if(pLead){const l=getLeads().find(x=>x.id===pLead.value);const prev=$('#v94PbPreview');if(prev)prev.innerHTML=renderPBPreview(currentPB(),l)}})}
function renderHomeEnhancement(){injectVersionChip()}
function ensureDrawer(){let back=$('#v94DrawerBackdrop'), dr=$('#v94LeadDrawer');if(!back){back=D.createElement('div');back.id='v94DrawerBackdrop';back.className='v94-drawer-backdrop';D.body.appendChild(back)}if(!dr){dr=D.createElement('aside');dr.id='v94LeadDrawer';dr.className='v94-drawer';D.body.appendChild(dr)}return {back,dr}}
function openLeadDrawer(id){const {back,dr}=ensureDrawer();const pipes=getPipeStages(), fus=getFuStages();let leads=getLeads();let isNew=id==='new';let l=isNew?normLead({id:uid('lead'),empresa:'',nome:'',pipeline:pipes[0],followup:fus[0],proximaData:today(),proximaHora:'10:00'}):(leads.find(x=>x.id===id)||leads[0]);if(!l)return;dr.innerHTML='<div class="v94-drawer-head"><div><div class="v94-eyebrow">Ficha única do lead</div><h2>'+(isNew?'Novo lead':esc(l.empresa||l.nome))+'</h2><p class="v94-muted">Qualquer alteração aqui atualiza Leads, Pipeline, Follow-up, Ligações e Métricas.</p></div><button class="v94-btn" data-v94-drawer-close>Fechar</button></div><div class="v94-drawer-body" data-v94-edit-lead="'+esc(l.id)+'" data-new="'+(isNew?'1':'0')+'"><div class="v94-fieldgrid"><div class="v94-field"><label>Empresa</label><input data-lead-field="empresa" value="'+esc(l.empresa)+'"></div><div class="v94-field"><label>Nome</label><input data-lead-field="nome" value="'+esc(l.nome)+'"></div><div class="v94-field"><label>Telefone</label><input data-lead-field="telefone" value="'+esc(l.telefone)+'"></div><div class="v94-field"><label>Cidade</label><input data-lead-field="cidade" value="'+esc(l.cidade)+'"></div><div class="v94-field"><label>Segmento</label><input data-lead-field="segmento" value="'+esc(l.segmento)+'"></div><div class="v94-field"><label>Origem</label><input data-lead-field="origem" value="'+esc(l.origem)+'"></div><div class="v94-field"><label>Campanha</label><input data-lead-field="campanha" value="'+esc(l.campanha)+'"></div><div class="v94-field"><label>Responsável</label><input data-lead-field="responsavel" value="'+esc(l.responsavel)+'"></div><div class="v94-field"><label>Valor</label><input type="number" data-lead-field="valor" value="'+esc(l.valor)+'"></div><div class="v94-field"><label>Pipeline</label><select data-lead-field="pipeline">'+pipes.map(p=>'<option '+(l.pipeline===p?'selected':'')+'>'+esc(p)+'</option>').join('')+'</select></div><div class="v94-field"><label>Follow-up</label><select data-lead-field="followup">'+fus.map(f=>'<option '+(l.followup===f?'selected':'')+'>'+esc(f)+'</option>').join('')+'</select></div><div class="v94-field"><label>Prioridade</label><select data-lead-field="prioridade">'+['Baixa','Média','Alta'].map(p=>'<option '+(l.prioridade===p?'selected':'')+'>'+p+'</option>').join('')+'</select></div><div class="v94-field"><label>Próxima data</label><input type="date" data-lead-field="proximaData" value="'+esc(l.proximaData)+'"></div><div class="v94-field"><label>Hora</label><input type="time" data-lead-field="proximaHora" value="'+esc(l.proximaHora)+'"></div><div class="v94-field"><label>Último resultado</label><input data-lead-field="ultimoResultado" value="'+esc(l.ultimoResultado)+'"></div></div><div class="v94-field"><label>Observações</label><textarea data-lead-field="observacoes">'+esc(l.observacoes)+'</textarea></div><div class="v94-toolbar"><button class="v94-btn primary" data-v94-save-lead>Salvar ficha</button><button class="v94-btn soft" data-v94-quick="call">Abrir em Ligações</button><button class="v94-btn soft" data-v94-quick="followup">Criar Follow-up hoje</button><button class="v94-btn soft" data-v94-quick="proposal">Enviar para Proposta</button><button class="v94-btn danger" data-v94-quick="lost">Marcar perdido</button></div><div class="v94-panel"><h2>Histórico</h2>'+((l.historico||[]).slice(-12).reverse().map(h=>'<div class="v94-event"><b>'+esc(h.tipo||'Evento')+' — '+esc(h.resultado||'')+'</b><div>'+esc(h.data||'')+' '+esc(h.hora||'')+' · '+esc(h.obs||'')+'</div></div>').join('')||'<div class="v94-empty">Sem histórico ainda.</div>')+'</div></div>';back.classList.add('active');dr.classList.add('active');}
function closeDrawer(){const b=$('#v94DrawerBackdrop'),d=$('#v94LeadDrawer');if(b)b.classList.remove('active');if(d)d.classList.remove('active')}
function collectDrawerLead(){const wrap=$('[data-v94-edit-lead]');if(!wrap)return null;let l={id:wrap.dataset.v94EditLead};$$('[data-lead-field]',wrap).forEach(i=>{l[i.dataset.leadField]=i.value});l.valor=Number(l.valor||0);return {lead:normLead(l),isNew:wrap.dataset.new==='1'};}
function saveDrawerLead(extra){const data=collectDrawerLead();if(!data)return null;let leads=getLeads();let i=leads.findIndex(x=>x.id===data.lead.id);let current=i>=0?leads[i]:data.lead;let merged=Object.assign({},current,data.lead);merged.historico=Array.isArray(current.historico)?current.historico:[];if(extra){Object.assign(merged,extra.fields||{});merged.historico=merged.historico.concat(extra.event||[])}if(i>=0)leads[i]=merged;else leads.push(merged);saveLeads(leads);refreshCurrent();openLeadDrawer(merged.id);return merged;}
function refreshCurrent(){if(currentView==='leads')renderLeads();if(currentView==='pipeline')renderPipeline();if(currentView==='metricas')renderMetricas();if(currentView==='playbooks')renderPlaybooks();}
function bindGlobal(){D.addEventListener('click',e=>{const open=e.target.closest('[data-v95-open-lead],[data-v93-open-lead]');if(open){e.preventDefault();e.stopPropagation();openLeadDrawer(open.getAttribute('data-v95-open-lead')||open.getAttribute('data-v93-open-lead'));return}if(e.target.closest('[data-v94-drawer-close]')||e.target.id==='v94DrawerBackdrop'){closeDrawer();return}if(e.target.closest('[data-v94-save-lead]')){saveDrawerLead({event:[{tipo:'Ficha',resultado:'Dados atualizados',data:today(),hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}),obs:'Atualizado na ficha única V94.'}]});return}const quick=e.target.closest('[data-v94-quick]');if(quick){const type=quick.dataset.v94Quick;let event={tipo:'Ação',resultado:type,data:today(),hora:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}),obs:'Ação rápida pela ficha única.'};let fields={};if(type==='followup'){fields.followup='Retorno marcado';fields.proximaData=today();event.resultado='Follow-up criado para hoje'}if(type==='proposal'){fields.pipeline='Proposta';fields.followup='Proposta enviada';event.resultado='Movido para Proposta'}if(type==='lost'){fields.pipeline='Perdido';fields.followup='Encerrado';event.resultado='Marcado como perdido'}const lead=saveDrawerLead({fields,event:[event]});if(type==='call'){closeDrawer();route('ligacoes')}return}const nav=e.target.closest('[data-view],[data-go-view],a[href^="#"]');if(nav){let v=nav.getAttribute('data-view')||nav.getAttribute('data-go-view')||(nav.getAttribute('href')||'').replace('#','');if(['leads','novo-lead','playbooks','metricas','dashboard','perdas','garimpo','ligacoes','cadencias','inicio'].includes(v)){setTimeout(()=>route(v),0)}}},true);}
function downloadJSON(data,name){const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});const a=D.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1200)}
function copyText(t){try{navigator.clipboard.writeText(t||'')}catch(e){const ta=D.createElement('textarea');ta.value=t||'';D.body.appendChild(ta);ta.select();D.execCommand('copy');ta.remove()}}
function injectVersionChip(){if($('#v94VersionChip'))return;const chip=D.createElement('div');chip.id='v94VersionChip';chip.className='v94-version-chip';chip.textContent='V95 automações internas';D.body.appendChild(chip)}
function cleanNav(){ $$('[data-view="dashboard"],[data-view="perdas"],[data-go-view="dashboard"],[data-go-view="perdas"]').forEach(n=>{if((n.className||'').toString().match(/nav-item|rail-btn|tab/)){n.remove()}else{n.setAttribute('data-view','metricas');n.setAttribute('data-go-view','metricas')}}); }
function boot(){D.body&&D.body.classList.add('v94-official');cleanNav();injectVersionChip();['leads','playbooks','pipeline','metricas'].forEach(id=>{const el=$('#'+id);if(el){el.classList.remove('v79-playbooks-view','v82-playbooks-section','v91-playbooks-section','v881-pipeline-v79-imagem','v93-view');el.classList.add('v94-official-view','v94-'+id+'-view')}});bindGlobal();const hash=(location.hash||'').replace('#','');const active=hash||$('.view.active')?.id||'inicio';if(['leads','novo-lead','pipeline','playbooks','metricas','dashboard','perdas'].includes(active))route(active);else if(active==='inicio')renderHomeEnhancement();setTimeout(()=>{['playbooks','leads','pipeline','metricas'].forEach(id=>{const el=$('#'+id);if(el&&(/Carregando módulo|^\s*$/.test(el.textContent||''))){if(id==='playbooks')renderPlaybooks();if(id==='leads')renderLeads();if(id==='pipeline')renderPipeline();if(id==='metricas')renderMetricas();}})},250)}
const previousSetView=window.setView;
window.CRMV94Official={route,renderLeads,renderPipeline,renderMetricas,renderPlaybooks,openLeadDrawer,getLeads,saveLeads,getPlaybooks,savePlaybooks,version:VERSION,map:{leads:'V94 Central de Leads',pipeline:'V65 Pipeline Dados Reais',playbooks:'V94 Playbook Limpo',metricas:'V94 Métricas Executivas',cadencias:'V92.1/V93.2 Follow-up protegido',ligacoes:'V93 Ligações protegidas',garimpo:'V93 Garimpo protegido'}};
window.setView=function(view){if(['leads','novo-lead','pipeline','playbooks','metricas','dashboard','perdas','garimpo','ligacoes','cadencias','inicio'].includes(String(view))){route(String(view));return}if(typeof previousSetView==='function')return previousSetView.apply(this,arguments);setOnlyView(String(view));};
try{setView=window.setView}catch(e){}
if(D.readyState==='loading')D.addEventListener('DOMContentLoaded',boot,{once:true});else boot();
})();
